using System.Diagnostics;
using System.Runtime.CompilerServices;
using TextAnalysis;

const string SampleText =
    "The quick brown fox jumps over the lazy dog " +
    "A stitch in time saves nine " +
    "To be or not to be that is the question " +
    "All that glitters is not gold " +
    "The quick brown fox jumps over the lazy dog again and again " +
    "Performance benchmarking is important for understanding runtime characteristics " +
    "Developers should measure before optimizing code paths " +
    "The rain in Spain stays mainly in the plain " +
    "Every good boy does fine when practicing scales daily " +
    "Supercalifragilisticexpialidocious is a very long word indeed";

var analyzer = new TextAnalyzer(SampleText);

const int WarmupIterations = 500_000;
const int MeasuredIterations = 5_000_000;
const int Runs = 5;

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Warmup: {WarmupIterations:N0} iterations, Measured: {MeasuredIterations:N0} iterations, Runs: {Runs}");
Console.WriteLine();

RunBenchmark("AverageWordLength", () => analyzer.AverageWordLength());
RunBenchmark("WordLengthHistogram", () => analyzer.WordLengthHistogram());
RunBenchmark("UniqueWordCount", () => analyzer.UniqueWordCount());

[MethodImpl(MethodImplOptions.NoInlining)]
static void RunBenchmark(string name, Func<object?> action)
{
    // Warmup
    for (int i = 0; i < WarmupIterations; i++)
        action();

    var times = new double[Runs];
    for (int run = 0; run < Runs; run++)
    {
        var sw = Stopwatch.StartNew();
        for (int i = 0; i < MeasuredIterations; i++)
            action();
        sw.Stop();
        times[run] = sw.Elapsed.TotalNanoseconds / MeasuredIterations;
    }

    Array.Sort(times);
    double median = times[Runs / 2];
    double min = times[0];
    double max = times[Runs - 1];
    Console.WriteLine($"{name,-25} | Median: {median,8:F2} ns | Min: {min,8:F2} ns | Max: {max,8:F2} ns");
}

